// 分页响应基础类型
export interface PaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

// 用户信息
export interface User {
  id: number;
  name: string;
  email: string;
  createdAt?: string;
}

// 商品分类
export interface Category {
  id: number;
  name: string;
  slug: string;
  description?: string;
}

// 商品
export interface Product {
  id: number;
  name: string;
  description?: string;
  price: number;
  imageUrl?: string;
  stock?: number;
  categoryId: number;
  categoryName: string;
  createdAt?: string;
  updatedAt?: string;
}

// 购物车项
export interface CartItem {
  productId: number;
  name: string;
  price: number;
  quantity: number;
  imageUrl: string;
  stock?: number;
}

// 购物车
export interface Cart {
  items: CartItem[];
  total: number;
}

// 添加购物车请求
export interface AddToCartRequest {
  productId: number;
  quantity: number;
}

// 更新购物车项请求
export interface UpdateCartItemRequest {
  productId: number;
  quantity: number;
}

