// 订单项
export interface OrderItem {
  productId: number;
  name: string;
  price: number;
  quantity: number;
  imageUrl: string;
}

// 订单
export interface Order {
  id: number;
  userId: number;
  items: OrderItem[];
  total: number;
  status: OrderStatus;
  shippingAddress?: string;
  note?: string;
  createdAt: string;
  updatedAt?: string;
}

