// 页面组件
type Page = 'products' | 'product-detail' | 'cart' | 'orders' | 'login' | 'register';

interface AuthProviderProps {
  children: ReactNode;
  onAuthChange: (user: User | null) => void;
}

const AuthProvider = ({ children, onAuthChange }: AuthProviderProps) => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(() => localStorage.getItem('token'));
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (token) {
      apiClient.setToken(token);
      apiClient.getCurrentUser()
        .then(setUser)
        .catch(() => {
          localStorage.removeItem('token');
          setToken(null);
        })
        .finally(() => setIsLoading(false));
    } else {
      setIsLoading(false);
    }
  }, [token]);

  const login = async (email: string, password: string) => {
    const response = await apiClient.login(email, password);
    localStorage.setItem('token', response.token);
    setToken(response.token);
    setUser(response.user);
    onAuthChange(response.user);
  };

  const register = async (name: string, email: string, password: string) => {
    const response = await apiClient.register(name, email, password);
    localStorage.setItem('token', response.token);
    setToken(response.token);
    setUser(response.user);
    onAuthChange(response.user);
  };

  const logout = () => {
    localStorage.removeItem('token');
    setToken(null);
    setUser(null);
    onAuthChange(null);
  };

  return (
    <AuthContext.Provider value={{ user, token, login, register, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

const CartProvider = ({ children }: { children: ReactNode }) => {
  const [cart, setCart] = useState<Cart>({ items: [], total: 0 });

  const refreshCart = async () => {
    try {
      const cartData = await apiClient.getCart();
      setCart(cartData);
    } catch (error) {
      console.error('Failed to fetch cart:', error);
    }
  };

  const addToCart = async (productId: number, quantity: number) => {
    await apiClient.addToCart({ productId, quantity });
    await refreshCart();
  };

  const updateCartItem = async (productId: number, quantity: number) => {
    await apiClient.updateCartItem({ productId, quantity });
    await refreshCart();
  };

  const removeFromCart = async (productId: number) => {
    await apiClient.removeFromCart(productId);
    await refreshCart();
  };

  const clearCart = async () => {
    await apiClient.clearCart();
    setCart({ items: [], total: 0 });
  };

  useEffect(() => {
    refreshCart();
  }, []);

  return (
    <CartContext.Provider value={{ cart, addToCart, updateCartItem, removeFromCart, clearCart, refreshCart }}>
      {children}
    </CartContext.Provider>
  );
};

