// 商品详情页面
const ProductDetailPage = ({ productId, onNavigate }: { productId: number; onNavigate: (page: Page, productId?: number) => void }) => {
  const { addToCart } = useCart();
  const [product, setProduct] = useState<Product | null>(null);
  const [quantity, setQuantity] = useState(1);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  useEffect(() => {
    const fetchProduct = async () => {
      setIsLoading(true);
      try {
        const data = await apiClient.getProduct(productId);
        setProduct(data);
      } catch (err: any) {
        setError(err.message || '获取商品详情失败');
      } finally {
        setIsLoading(false);
      }
    };
    fetchProduct();
  }, [productId]);

  const handleAddToCart = async () => {
    if (!product) return;
    setIsAdding(true);
    try {
      await addToCart(product.id, quantity);
      setSuccess('已添加到购物车');
      setTimeout(() => setSuccess(''), 3000);
    } catch (err: any) {
      setError(err.message || '添加到购物车失败');
    } finally {
      setIsAdding(false);
    }
  };

  if (isLoading) {
    return <div style={{ textAlign: 'center', padding: '2rem' }}>加载中...</div>;
  }

  if (error || !product) {
    return <div style={styles.error}>{error || '商品不存在'}</div>;
  }

  return (
    <div style={styles.card}>
      <button
        style={{ ...styles.button, ...styles.buttonSecondary, marginBottom: '1rem' }}
        onClick={() => onNavigate('products')}
      >
        返回商品列表
      </button>

      <div style={{ display: 'flex', gap: '2rem', flexWrap: 'wrap' }}>
        <div style={{ flex: '1 1 300px' }}>
          <img
            src={product.imageUrl || 'https://via.placeholder.com/400x300?text=No+Image'}
            alt={product.name}
            style={{ width: '100%', borderRadius: '8px' }}
          />
        </div>
        <div style={{ flex: '1 1 300px' }}>
          <h1 style={{ marginTop: 0 }}>{product.name}</h1>
          <p style={{ color: '#666' }}>分类: {product.categoryName}</p>
          <div style={styles.price}>¥{product.price.toFixed(2)}</div>
          <p>库存: {product.stock ?? '充足'}</p>
          <p>{product.description || '暂无商品描述'}</p>

          {success && <div style={styles.success}>{success}</div>}
          {error && <div style={styles.error}>{error}</div>}

          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginTop: '1.5rem' }}>
            <input
              type="number"
              min="1"
              max={product.stock || 99}
              value={quantity}
              onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
              style={{ ...styles.input, width: '80px' }}
            />
            <button
              style={styles.button}
              onClick={handleAddToCart}
              disabled={isAdding}
            >
              {isAdding ? '添加中...' : '加入购物车'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// 购物车页面
const CartPage = ({ onNavigate }: { onNavigate: (page: Page) => void }) => {
  const { cart, updateCartItem, removeFromCart, clearCart } = useCart();
  const { user } = useAuth();
  const [isOrdering, setIsOrdering] = useState(false);
  const [shippingAddress, setShippingAddress] = useState('');
  const [note, setNote] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleCheckout = async () => {
    if (!user) {
      setError('请先登录');
      return;
    }
    if (cart.items.length === 0) {
      setError('购物车为空');
      return;
    }
    if (!shippingAddress.trim()) {
      setError('请填写收货地址');
      return;
    }

    setIsOrdering(true);
    setError('');
    try {
      await apiClient.createOrder({
        shippingAddress,
        note,
      });
      await clearCart();
      setSuccess('订单创建成功！');
      setShippingAddress('');
      setNote('');
      setTimeout(() => {
        onNavigate('orders');
      }, 1500);
    } catch (err: any) {
      setError(err.message || '创建订单失败');
    } finally {
      setIsOrdering(false);
    }
  };

  if (cart.items.length === 0) {
    return (
      <div style={styles.card}>
        <h2 style={{ marginTop: 0 }}>购物车</h2>
        <p style={{ textAlign: 'center', color: '#666' }}>购物车是空的</p>
        <div style={{ textAlign: 'center' }}>
          <button style={styles.button} onClick={() => onNavigate('products')}>
            去购物
          </button>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div style={styles.card}>
        <h2 style={{ marginTop: 0 }}>购物车</h2>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>商品</th>
              <th style={styles.th}>价格</th>
              <th style={styles.th}>数量</th>
              <th style={styles.th}>小计</th>
              <th style={styles.th}>操作</th>
            </tr>
          </thead>
          <tbody>
            {cart.items.map((item) => (
              <tr key={item.productId}>
                <td style={styles.td}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <img
                      src={item.imageUrl || 'https://via.placeholder.com/50x50?text=No'}
                      alt={item.name}
                      style={{ width: '50px', height: '50px', objectFit: 'cover', borderRadius: '4px' }}
                    />
                    <span>{item.name}</span>
                  </div>
                </td>
                <td style={styles.td}>¥{item.price.toFixed(2)}</td>
                <td style={styles.td}>
                  <input
                    type="number"
                    min="1"
                    value={item.quantity}
                    onChange={(e) => updateCartItem(item.productId, parseInt(e.target.value) || 1)}
                    style={{ ...styles.input, width: '60px' }}
                  />
                </td>
                <td style={styles.td}>¥{(item.price * item.quantity).toFixed(2)}</td>
                <td style={styles.td}>
                  <button
                    style={{ ...styles.button, ...styles.buttonDanger }}
                    onClick={() => removeFromCart(item.productId)}
                  >
                    删除
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{ textAlign: 'right', marginTop: '1rem', fontSize: '1.25rem' }}>
          总计: <span style={{ color: '#e74c3c', fontWeight: 'bold' }}>¥{cart.total.toFixed(2)}</span>
        </div>
      </div>

      <div style={styles.card}>
        <h3>确认订单</h3>
        {error && <div style={styles.error}>{error}</div>}
        {success && <div style={styles.success}>{success}</div>}

        <div style={styles.formGroup}>
          <label style={styles.label}>收货地址 *</label>
          <textarea
            value={shippingAddress}
            onChange={(e) => setShippingAddress(e.target.value)}
            style={{ ...styles.input, minHeight: '80px' }}
            placeholder="请输入详细收货地址"
            required
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>备注</label>
          <textarea
            value={note}
            onChange={(e) => setNote(e.target.value)}
            style={{ ...styles.input, minHeight: '60px' }}
            placeholder="选填"
          />
        </div>

        <button
          style={styles.button}
          onClick={handleCheckout}
          disabled={isOrdering}
        >
          {isOrdering ? '提交中...' : '提交订单'}
        </button>
      </div>
    </div>
  );
};

