                    </p>
                  )}
                </div>
                <div style={styles.price}>总计: ¥{order.total.toFixed(2)}</div>
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  );
};

// 主应用
const AppContent = () => {
  const [currentPage, setCurrentPage] = useState<Page>('products');
  const [selectedProductId, setSelectedProductId] = useState<number | null>(null);
  const [user, setUser] = useState<User | null>(null);

  const { user: authUser, logout } = useAuth();

  useEffect(() => {
    setUser(authUser);
  }, [authUser]);

  const handleNavigate = (page: Page, productId?: number) => {
    setCurrentPage(page);
    if (productId) {
      setSelectedProductId(productId);
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'products':
        return <ProductsPage onNavigate={handleNavigate} />;
      case 'product-detail':
        return selectedProductId ? (
          <ProductDetailPage productId={selectedProductId} onNavigate={handleNavigate} />
        ) : (
          <ProductsPage onNavigate={handleNavigate} />
        );
      case 'cart':
        return <CartPage onNavigate={handleNavigate} />;
      case 'orders':
        return <OrdersPage onNavigate={handleNavigate} />;
      case 'login':
        return <LoginPage />;
      case 'register':
        return <RegisterPage />;
      default:
        return <ProductsPage onNavigate={handleNavigate} />;
    }
  };

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1 style={{ margin: 0, fontSize: '1.5rem' }}>电商平台</h1>
        <nav style={styles.nav}>
          <span
            style={{
              ...styles.navLink,
              ...(currentPage === 'products' || currentPage === 'product-detail' ? styles.navLinkActive : {}),
            }}
            onClick={() => handleNavigate('products')}
          >
            商品
          </span>
          <span
            style={{
              ...styles.navLink,
              ...(currentPage === 'cart' ? styles.navLinkActive : {}),
            }}
            onClick={() => handleNavigate('cart')}
          >
            购物车
          </span>
          {user ? (
            <>
              <span
                style={{
                  ...styles.navLink,
                  ...(currentPage === 'orders' ? styles.navLinkActive : {}),
                }}
                onClick={() => handleNavigate('orders')}
              >
                我的订单
              </span>
              <span style={styles.navLink} onClick={logout}>
                退出 ({user.name})
              </span>
            </>
          ) : (
            <>
              <span
                style={{
                  ...styles.navLink,
                  ...(currentPage === 'login' ? styles.navLinkActive : {}),
                }}
                onClick={() => handleNavigate('login')}
              >
                登录
              </span>
              <span
                style={{
                  ...styles.navLink,
                  ...(currentPage === 'register' ? styles.navLinkActive : {}),
                }}
                onClick={() => handleNavigate('register')}
              >
                注册
              </span>
            </>
          )}
        </nav>
      </header>
      <main style={styles.main}>{renderPage()}</main>
    </div>
  );
};

// App wrapper with providers
export default function App() {
  const [user, setUser] = useState<User | null>(null);

  return (
    <AuthProvider onAuthChange={setUser}>
      <CartProvider>
        <AppContent />
      </CartProvider>
    </AuthProvider>
  );
}

import type {
  User,
  Product,
  ProductListResponse,
  Category,
  Cart,
  CartItem,
  AddToCartRequest,
  UpdateCartItemRequest,
  Order,
  OrderListResponse,
  AuthResponse,
  LoginRequest,
  RegisterRequest,
  ApiError,
} from '../types';

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:3001/api';

export class ApiClient {
  private token: string | null = null;

  setToken(token: string | null) {
    this.token = token;
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    const headers: HeadersInit = {
      'Content-Type': 'application/json',
      ...options.headers,
    };

    if (this.token) {
      (headers as Record<string, string>)['Authorization'] = `Bearer ${this.token}`;
    }

    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers,
    });

    if (!response.ok) {
      const error: ApiError = await response.json().catch(() => ({
        message: `请求失败: ${response.status} ${response.statusText}`,
      }));
      throw new Error(error.message);
    }

    return response.json();
  }

  // 认证相关
  async login(email: string, password: string): Promise<AuthResponse> {
    const response = await this.request<AuthResponse>('/auth/login', {
      method: 'POST',
      body: JSON.stringify({ email, password }),
    });
    this.setToken(response.token);
    return response;
  }

  async register(name: string, email: string, password: string): Promise<AuthResponse> {
    const response = await this.request<AuthResponse>('/auth/register', {
      method: 'POST',
      body: JSON.stringify({ name, email, password }),
    });
    this.setToken(response.token);
    return response;
  }

  async getCurrentUser(): Promise<User> {
    return this.request<User>('/auth/me');
  }

  // 商品相关
  async getProducts(categoryId?: number, page = 1, pageSize = 20): Promise<ProductListResponse> {
    const params = new URLSearchParams();
    if (categoryId) params.append('categoryId', String(categoryId));
    params.append('page', String(page));
    params.append('pageSize', String(pageSize));

    return this.request<ProductListResponse>(`/products?${params.toString()}`);
  }

  async getProduct(id: number): Promise<Product> {
    return this.request<Product>(`/products/${id}`);
  }

  async getCategories(): Promise<Category[]> {
    return this.request<Category[]>('/categories');
  }

  // 购物车相关
  async getCart(): Promise<Cart> {
    return this.request<Cart>('/cart');
  }

  async addToCart(data: AddToCartRequest): Promise<Cart> {
    return this.request<Cart>('/cart/items', {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  async updateCartItem(data: UpdateCartItemRequest): Promise<Cart> {
    return this.request<Cart>(`/cart/items/${data.productId}`, {
      method: 'PUT',
      body: JSON.stringify({ quantity: data.quantity }),
    });
  }

  async removeFromCart(productId: number): Promise<Cart> {
    return this.request<Cart>(`/cart/items/${productId}`, {
      method: 'DELETE',
    });
  }

  async clearCart(): Promise<void> {
    await this.request<void>('/cart', {
      method: 'DELETE',
    });
  }

  // 订单相关
  async getOrders(page = 1, pageSize = 10): Promise<OrderListResponse> {
    const params = new URLSearchParams();
    params.append('page', String(page));
    params.append('pageSize', String(pageSize));

    return this.request<OrderListResponse>(`/orders?${params.toString()}`);
  }

  async getOrder(id: number): Promise<Order> {
    return this.request<Order>(`/orders/${id}`);
  }

  async createOrder(data: { shippingAddress: string; note?: string }): Promise<Order> {
    return this.request<Order>('/orders', {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  async cancelOrder(id: number): Promise<Order> {
    return this.request<Order>(`/orders/${id}/cancel`, {
      method: 'POST',
    });
  }
}

export const apiClient = new ApiClient();

// 为方便使用，也导出一些快捷方法
export const auth = {
  login: (email: string, password: string) => apiClient.login(email, password),
  register: (name: string, email: string, password: string) => apiClient.register(name, email, password),
  getCurrentUser: () => apiClient.getCurrentUser(),
  logout: () => apiClient.setToken(null),
};

export const products = {
  list: (categoryId?: number, page?: number, pageSize?: number) => 
    apiClient.getProducts(categoryId, page, pageSize),
  get: (id: number) => apiClient.getProduct(id),
  categories: () => apiClient.getCategories(),
};

export const cart = {
  get: () => apiClient.getCart(),
  add: (productId: number, quantity: number) => 
    apiClient.addToCart({ productId, quantity }),
  update: (productId: number, quantity: number) => 
    apiClient.updateCartItem({ productId, quantity }),
  remove: (productId: number) => apiClient.removeFromCart(productId),
  clear: () => apiClient.clearCart(),
};

export const orders = {
  list: (page?: number, pageSize?: number) => apiClient.getOrders(page, pageSize),
  get: (id: number) => apiClient.getOrder(id),
  create: (data: { shippingAddress: string; note?: string }) => apiClient.createOrder(data),
  cancel: (id: number) => apiClient.cancelOrder(id),
};

